import type { Pattern } from '../types.js';
import { jsxText, regionLabel } from '../util.js';

const pattern: Pattern = {
  name: 'clickable/pill',
  group: 'clickable',
  score(region) {
    const name = region.name.trim();
    const nameLength = name.length;
    if (nameLength > 30) return 0;

    // pill-text signal: tag-like content, not a multi-word phrase
    const isPillText =
      nameLength <= 8 ||
      /^\S+$/.test(name) ||
      /^[\d+\-*#%]+$/.test(name);

    if (!region.bounds) {
      return isPillText ? 35 : 15;
    }

    const { w, h } = region.bounds;
    const compact = w >= 40 && w <= 150 && h < 36;

    // strong pill: tag-like text in compact bounds ú wins over button (90 max) and link (95 max)
    if (isPillText && compact) return 100;

    // pill-text without compact bounds, or compact without pill-text ú stay below button/link
    if (isPillText) return 25;
    if (compact) return 40;
    return 10;
