// Trainer ú grade canvas-engine pattern picker against leaf-tag ground truth.
//
// "Truth" = the tag at the end of region.selector (a, button, h2, header...).
// The browser wrote that tag ú the cascade did not ú so it's an independent
// label we can grade the picker against without trusting the producer.
//
// Two levels of grading:
//   GROUP-LEVEL ú is the picked pattern in the right group? (clickable/heading/...)
//   PATTERN-LEVEL ú within the group, is the right SUB-pattern firing?
//                   (e.g. <h1>  heading/hero, <a>  clickable/link)
//
// For pattern-level we use an "acceptable set" rather than a single answer
// because some leaf tags map cleanly to one pattern (header  landmark/header)
// while others have multiple valid renderings (a tag-like <button> can be
// clickable/pill or clickable/button - both reasonable).
//
// Run: cd services/canvas-engine && npx tsx test/trainer-vs-truth.mjs

import { readFileSync, readdirSync, statSync } from 'node:fs';
import { join, basename } from 'node:path';
import { anatomyV1Schema } from '../src/adapter/v1-schema.ts';
import { buildPatternRegistry, pickPattern } from '../src/pattern-library/index.ts';

const CAPTURE_ROOTS = [
  'C:/Users/bruke/web-audit/.tmp',
  'C:/Users/bruke/web-audit/.canvas',
  'C:/Users/bruke/Pre Atlas/.tmp',
];
const EXTRA_FILES = [
  'C:/Users/bruke/OneDrive/Desktop/anatomy-localhost-c-news-ycombinator-com-1b-moboruxv- (1).json',
];

const TAG_TO_GROUP = {
  a: 'clickable', button: 'clickable',
  h1: 'heading', h2: 'heading', h3: 'heading',
  h4: 'heading', h5: 'heading', h6: 'heading',
  header: 'landmark', nav: 'landmark', aside: 'landmark',
  footer: 'landmark', main: 'landmark', section: 'landmark',
  form: 'form', textarea: 'form', select: 'form', input: 'form',
  ul: 'list', ol: 'list',
  article: 'card',
};

const CTA_RE = /\b(subscribe|sign\s?up|get\s?started|start\s?now|try\s?(it\s)?free|join|buy\s?now|download|install|get\s?the\s?app|book\s?a\s?demo)\b/i;

// Acceptable pattern set per region ú multi-membership where the choice is
// stylistic (link vs pill, button vs pill). Returns null if leaf tag is not
// in our truth set (indecidable).
function acceptablePatterns(region, leafTag) {
  const w = region.bounds?.w ?? 0;
  const h = region.bounds?.h ?? 0;
  const name = (region.name || '').trim();
  const nameL = name.toLowerCase();
  const compact = w > 0 && w >= 40 && w <= 150 && h > 0 && h < 36;
  const iconSize = w > 0 && w < 48 && h > 0 && h < 48 && name.length <= 4;
  const tagLikeText = name.length > 0 && (name.length <= 8 || /^\S+$/.test(name));

  // landmarks ú single-answer
  if (leafTag === 'header') return new Set(['landmark/header']);
  if (leafTag === 'nav')    return new Set(['landmark/nav']);
  if (leafTag === 'footer') return new Set(['landmark/footer']);
  if (leafTag === 'aside')  return new Set(['landmark/aside']);
  if (leafTag === 'section' || leafTag === 'main') return new Set(['landmark/section']);

  // headings
  if (leafTag === 'h1') return new Set(['heading/hero']);
  if (/^h[2-6]$/.test(leafTag)) {
    const both = new Set(['heading/tagged', 'heading/eyebrow']);
    return both;
  }

  // clickables ú multi-answer (a vs button preserves anchor semantics + pill is stylistic)
  if (leafTag === 'a' || leafTag === 'button') {
    if (iconSize) return new Set(['clickable/icon-button']);
    if (CTA_RE.test(nameL) && (w > 200 || h > 50)) return new Set(['clickable/cta']);

    const out = new Set();
    if (leafTag === 'a') out.add('clickable/link');
    if (leafTag === 'button') out.add('clickable/button');
    if (compact && tagLikeText) out.add('clickable/pill');
    if (CTA_RE.test(nameL)) out.add('clickable/cta');
    return out;
  }

  // forms ú search/newsletter keyword routes, default stacked
  if (leafTag === 'form' || leafTag === 'input' || leafTag === 'textarea' || leafTag === 'select') {
    if (nameL.includes('search')) return new Set(['form/inline', 'form/stacked']);
    if (nameL.includes('subscribe') || nameL.includes('newsletter')) return new Set(['form/newsletter', 'form/stacked']);
    return new Set(['form/stacked', 'form/inline']);
  }

  // lists ú width/height shape selects variant, allow neighbor variants
  if (leafTag === 'ul' || leafTag === 'ol') {
    if (w > 600) return new Set(['list/grid', 'list/vertical']);
    if (h > 200) return new Set(['list/vertical', 'list/grid']);
    return new Set(['list/tags', 'list/vertical']);
  }

  if (leafTag === 'article') {
    const out = new Set(['card/content']);
    if (region.fetches?.length) out.add('card/action');
    if (/^\d+/.test(name)) out.add('card/stat');
    return out;
  }

  return null;
}

function leafTag(selector) {
  if (!selector) return null;
  const matches = [...selector.matchAll(/>\s*([a-zA-Z][a-zA-Z0-9-]*)(?:[:.\[#]|$)/g)];
  return matches.length ? matches[matches.length - 1][1].toLowerCase() : null;
}

function* walkAnatomyFiles(dir) {
  let entries;
  try { entries = readdirSync(dir); } catch { return; }
  for (const name of entries) {
    const full = join(dir, name);
    let s;
    try { s = statSync(full); } catch { continue; }
    if (s.isDirectory()) yield* walkAnatomyFiles(full);
    else if (name === 'anatomy.json') yield full;
  }
}

function findCaptures() {
  const out = [];
  for (const root of CAPTURE_ROOTS) for (const fp of walkAnatomyFiles(root)) out.push(fp);
  for (const fp of EXTRA_FILES) { try { statSync(fp); out.push(fp); } catch {} }
  return out;
}

function bar(value, max, width = 40) {
  const fill = max > 0 ? Math.round(width * value / max) : 0;
  return 'Ű'.repeat(fill) + 'ú'.repeat(width - fill);
}

function main() {
  const registry = buildPatternRegistry();
  const captures = findCaptures();
  console.log(`Loaded ${captures.length} captures from disk.\n`);

  // group-level
  let total = 0, gDecidable = 0, gCorrect = 0;
  const groupStats = {};
  const groupConfusion = new Map();

  // pattern-level
  let pDecidable = 0, pCorrect = 0;
  const patternStats = {};            // pattern  {fired, correctFires}
  const tagPatternMistakes = new Map(); // (tag  picked)  count
  const sampleMistakes = new Map();   // key  up to 5 samples
  const acceptanceWidth = { 1: 0, 2: 0, 3: 0, 4: 0 }; // truth-set size histogram

  for (const fp of captures) {
    let raw;
    try { raw = JSON.parse(readFileSync(fp, 'utf8')); } catch { continue; }
    const r = anatomyV1Schema.safeParse(raw);
    if (!r.success) continue;
    const env = r.data;
    const cap = (fp.split(/[\\/]/).slice(-2)[0] || '').slice(0, 30);

    for (const region of env.regions) {
      total++;
      const tag = leafTag(region.selector);
      const truthGroup = tag ? TAG_TO_GROUP[tag] : null;
      if (!truthGroup) continue;

      const pick = pickPattern(region, registry);

      // group grading
      gDecidable++;
      const groupOk = pick.group === truthGroup;
      if (groupOk) gCorrect++;
      groupStats[truthGroup] = groupStats[truthGroup] || { total: 0, correct: 0 };
      groupStats[truthGroup].total++;
      if (groupOk) groupStats[truthGroup].correct++;
      if (!groupConfusion.has(truthGroup)) groupConfusion.set(truthGroup, new Map());
      const cm = groupConfusion.get(truthGroup);
      cm.set(pick.group, (cm.get(pick.group) ?? 0) + 1);

      // pattern grading
      const accept = acceptablePatterns(region, tag);
      if (!accept) continue;
      pDecidable++;
      acceptanceWidth[Math.min(accept.size, 4)]++;
      const patternOk = accept.has(pick.pattern.name);
      if (patternOk) pCorrect++;

      patternStats[pick.pattern.name] = patternStats[pick.pattern.name] || { fired: 0, correctFires: 0 };
      patternStats[pick.pattern.name].fired++;
      if (patternOk) patternStats[pick.pattern.name].correctFires++;

      if (!patternOk) {
        const expected = [...accept].join(' | ');
        const key = `<${tag}>  ${pick.pattern.name}`;
        if (!sampleMistakes.has(key)) sampleMistakes.set(key, { expected, samples: [] });
        const slot = sampleMistakes.get(key);
        if (slot.samples.length < 5) slot.samples.push({
          cap,
          name: region.name?.slice(0, 36) || '',
          bounds: region.bounds && `${Math.round(region.bounds.w)}x${Math.round(region.bounds.h)}`,
          desc: region.desc?.slice(0, 24),
          score: pick.score,
        });
        const tk = `${tag}|${pick.pattern.name}`;
        tagPatternMistakes.set(tk, (tagPatternMistakes.get(tk) ?? 0) + 1);
      }
    }
  }

  console.log('='.repeat(78));
  console.log('GROUP-LEVEL ACCURACY');
  console.log('='.repeat(78));
  console.log(`Decidable: ${gDecidable} / ${total}   Correct: ${gCorrect} / ${gDecidable} = ${(100*gCorrect/gDecidable).toFixed(1)}%\n`);
  for (const [g, s] of Object.entries(groupStats).sort((a,b)=>b[1].total-a[1].total)) {
    const pct = (100*s.correct/s.total).toFixed(1).padStart(5);
    console.log(`  ${g.padEnd(10)} ${pct}%  ${bar(s.correct, s.total)}  (${s.correct}/${s.total})`);
  }

  console.log();
  console.log('='.repeat(78));
  console.log('PATTERN-LEVEL ACCURACY  (sub-pattern within correct group)');
  console.log('='.repeat(78));
  console.log(`Decidable: ${pDecidable}   Correct: ${pCorrect} / ${pDecidable} = ${(100*pCorrect/pDecidable).toFixed(1)}%`);
  console.log(`Truth-set size: 1${acceptanceWidth[1]}  2${acceptanceWidth[2]}  3${acceptanceWidth[3]}  4+${acceptanceWidth[4]}  (1 = single answer ú 2+ = stylistically flexible)\n`);

  console.log('Per-pattern fire rates (how often each pattern is chosen + how often it was acceptable):');
  const sortedPatterns = Object.entries(patternStats).sort((a,b)=>b[1].fired-a[1].fired);
  for (const [p, s] of sortedPatterns) {
    const pct = s.fired ? (100*s.correctFires/s.fired).toFixed(1).padStart(5) : ' n/a ';
    console.log(`  ${p.padEnd(22)} fires=${String(s.fired).padStart(4)}  acceptable=${String(s.correctFires).padStart(4)}  ${pct}%  ${bar(s.correctFires, s.fired)}`);
  }

  console.log();
  console.log('='.repeat(78));
  console.log('PATTERN-LEVEL MISTAKES  (picker chose unacceptable pattern for the leaf tag)');
  console.log('='.repeat(78));
  if (tagPatternMistakes.size === 0) {
    console.log('  none.');
  } else {
    const rows = [...tagPatternMistakes.entries()].sort((a,b)=>b[1]-a[1]);
    for (const [k, c] of rows) {
      const [tag, picked] = k.split('|');
      console.log(`  ${String(c).padStart(4)} x <${tag}> picked ${picked}`);
    }
  }

  console.log();
  console.log('='.repeat(78));
  console.log('SAMPLE PATTERN MISTAKES  (up to 3 examples each)');
  console.log('='.repeat(78));
  for (const [key, slot] of [...sampleMistakes.entries()].sort()) {
    console.log(`\n  ${key}`);
    console.log(`    expected: ${slot.expected}`);
    for (const s of slot.samples.slice(0, 3)) {
      console.log(`      ú "${s.name}" bounds=${s.bounds || '?'}${s.desc ? ' desc=' + s.desc : ''} (score ${s.score})`);
    }
  }

  console.log();
  console.log('='.repeat(78));
  console.log(`SUMMARY  group=${(100*gCorrect/gDecidable).toFixed(1)}% (${gCorrect}/${gDecidable})  ú  pattern=${(100*pCorrect/pDecidable).toFixed(1)}% (${pCorrect}/${pDecidable})`);
  console.log('='.repeat(78));
}

main();
